#include<iostream>#include<vector>#include<string>#include<algorithm>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        int n,c;        cin>>n>>c;        vector<int>a;        for(int i=1;i<=n;i++){            int x;            cin>>x;            x+=i;            a.push_back(x);        }        sort(a.begin(),a.end());        int j=0;        int cnt=0;        while(j<n && a[j]<=c){                cnt++;                c-=a[j];                j++;        }        cout<<cnt<<"\n";    }}